+                const key = try self.parseKey();
+                _ = key;
+
+                self.skipWhitespace();
+                if (self.pos >= self.source.len or self.source[self.pos] != ']') {
+                    return error.InvalidSyntax;
+                }
+                self.pos += 1;
+                if (is_array) {
+                    if (self.pos >= self.source.len or self.source[self.pos] != ']') {
+                        return error.InvalidSyntax;
+                    }
+                    self.pos += 1;
+                }
+
+                // Would navigate to/create the table here
+                current_table = &root;
+            } else if (c == '\n') {
+                self.pos += 1;
+                self.line += 1;
+                self.column = 1;
+            } else if (c != '#') {
+                // Key-value pair
+                const key = try self.parseKey();
+                self.skipWhitespace();
+
+                if (self.pos >= self.source.len or self.source[self.pos] != '=') {
+                    return error.InvalidSyntax;
+                }
+                self.pos += 1;
+                self.skipWhitespace();
+
+                const value = try self.parseValue();
+                try current_table.put(key, value);
+            }
+        }
+
+        return root;
+    }
