+    fn skipWhitespace(self: *Self) void {
+        while (self.pos < self.source.len) {
+            const c = self.source[self.pos];
+            if (c == ' ' or c == '\t') {
+                self.pos += 1;
+                self.column += 1;
+            } else {
+                break;
+            }
+        }
+    }
+
+    fn skipWhitespaceAndComments(self: *Self) void {
+        while (self.pos < self.source.len) {
+            const c = self.source[self.pos];
+            if (c == ' ' or c == '\t') {
+                self.pos += 1;
+                self.column += 1;
+            } else if (c == '#') {
+                // Skip to end of line
+                while (self.pos < self.source.len and self.source[self.pos] != '\n') {
+                    self.pos += 1;
+                }
+            } else if (c == '\n') {
+                self.pos += 1;
+                self.line += 1;
+                self.column = 1;
+            } else {
