+
+        if (is_float) {
+            const f = std.fmt.parseFloat(f64, num_str) catch return error.InvalidNumber;
+            return Value{ .float = f };
+        } else {
+            const i = std.fmt.parseInt(i64, num_str, 10) catch return error.InvalidNumber;
+            return Value{ .integer = i };
+        }
+    }
+
+    fn parseArray(self: *Self) !Value {
+        if (self.source[self.pos] != '[') return error.InvalidSyntax;
+        self.pos += 1;
+
+        var arr = std.ArrayList(Value).init(self.allocator);
+
+        while (self.pos < self.source.len) {
+            self.skipWhitespaceAndComments();
+            if (self.pos >= self.source.len) break;
+
+            if (self.source[self.pos] == ']') {
+                self.pos += 1;
+                break;
+            }
+
+            const value = try self.parseValue();
+            try arr.append(value);
+
+            self.skipWhitespaceAndComments();
+            if (self.pos < self.source.len and self.source[self.pos] == ',') {
+                self.pos += 1;
+            }
+        }
+
+        return Value{ .array = arr };
+    }
+
+    fn parseInlineTable(self: *Self) !Value {
+        if (self.source[self.pos] != '{') return error.InvalidSyntax;
+        self.pos += 1;
+
+        var tbl = std.StringHashMap(Value).init(self.allocator);
+
+        while (self.pos < self.source.len) {
+            self.skipWhitespace();
+            if (self.pos >= self.source.len) break;
+
+            if (self.source[self.pos] == '}') {
+                self.pos += 1;
+                break;
+            }
+
+            const key = try self.parseKey();
+            self.skipWhitespace();
+
+            if (self.pos >= self.source.len or self.source[self.pos] != '=') {
+                return error.InvalidSyntax;
+            }
+            self.pos += 1;
+            self.skipWhitespace();
+
+            const value = try self.parseValue();
+            try tbl.put(key, value);
+
+            self.skipWhitespace();
+            if (self.pos < self.source.len and self.source[self.pos] == ',') {
+                self.pos += 1;
+            }
+        }
+
+        return Value{ .table = tbl };
+    }
+};
+
+// ============================================================================
+// Public API
+// ============================================================================
+
+/// Parse a TOML string
+pub fn loads(allocator: std.mem.Allocator, s: []const u8) !std.StringHashMap(Value) {
+    var parser = Parser.init(allocator, s);
+    return parser.parse();
+}
+
+/// Parse a TOML file
+pub fn load(allocator: std.mem.Allocator, fp: std.fs.File) !std.StringHashMap(Value) {
+    const content = try fp.readToEndAlloc(allocator, std.math.maxInt(usize));
+    defer allocator.free(content);
+    return loads(allocator, content);
+}
+
+// ============================================================================
+// Module State
+// ============================================================================
+
+var initialized: bool = false;
+
+pub fn init() void {
+    if (initialized) return;
+    initialized = true;
+}
+
+pub fn reset() void {
+    initialized = false;
+}
